import{_ as e,o as a,c as r,ag as t}from"./chunks/framework.ePeAWSvT.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"matieres/sante/cours/infection-urinaire-sévère.md","filePath":"matieres/sante/cours/infection-urinaire-sévère.md"}'),n={name:"matieres/sante/cours/infection-urinaire-sévère.md"};function s(l,i,o,u,c,d){return a(),r("div",null,[...i[0]||(i[0]=[t('<h2 id="_1️⃣-definition" tabindex="-1">1️⃣ Définition <a class="header-anchor" href="#_1️⃣-definition" aria-label="Permalink to &quot;1️⃣ Définition&quot;">​</a></h2><p>L’infection urinaire sévère est une <strong>infection bactérienne des voies urinaires pouvant atteindre les reins (pyélonéphrite)</strong>.</p><hr><h2 id="_2️⃣-causes" tabindex="-1">2️⃣ Causes <a class="header-anchor" href="#_2️⃣-causes" aria-label="Permalink to &quot;2️⃣ Causes&quot;">​</a></h2><ul><li>Escherichia coli (majoritaire)</li><li>Staphylococcus saprophyticus</li><li>Anomalies anatomiques</li></ul><hr><h2 id="_3️⃣-symptomes" tabindex="-1">3️⃣ Symptômes <a class="header-anchor" href="#_3️⃣-symptomes" aria-label="Permalink to &quot;3️⃣ Symptômes&quot;">​</a></h2><ul><li>Fièvre élevée</li><li>Douleurs lombaires</li><li>Brûlures mictionnelles</li><li>Urines troubles ou sanglantes</li><li>Nausées, vomissements</li></ul><hr><h2 id="_4️⃣-diagnostic" tabindex="-1">4️⃣ Diagnostic <a class="header-anchor" href="#_4️⃣-diagnostic" aria-label="Permalink to &quot;4️⃣ Diagnostic&quot;">​</a></h2><ul><li>Analyse d’urines</li><li>ECBU (examen cytobactériologique des urines)</li><li>Hémoculture si grave</li><li>Échographie rénale si complications</li></ul><hr><h2 id="_5️⃣-traitement" tabindex="-1">5️⃣ Traitement <a class="header-anchor" href="#_5️⃣-traitement" aria-label="Permalink to &quot;5️⃣ Traitement&quot;">​</a></h2><ul><li>Antibiotiques adaptés</li><li>Hydratation abondante</li><li>Hospitalisation si pyélonéphrite sévère</li></ul><hr><h2 id="_6️⃣-role-infirmier" tabindex="-1">6️⃣ Rôle infirmier <a class="header-anchor" href="#_6️⃣-role-infirmier" aria-label="Permalink to &quot;6️⃣ Rôle infirmier&quot;">​</a></h2><ul><li>Surveillance des signes vitaux</li><li>Administration des antibiotiques</li><li>Suivi de la diurèse et des symptômes</li><li>Éducation sur l’hygiène urinaire</li></ul>',17)])])}const _=e(n,[["render",s]]);export{h as __pageData,_ as default};
